import pika
import time
import threading

class RabbitMQClient:
    def __init__(self, host='localhost', port=5672):
        self.host = host
        self.port = port

    def _connect(self):
        return pika.BlockingConnection(pika.ConnectionParameters(host=self.host, port=self.port))

class TaskPublisher(RabbitMQClient):
    def publish_task(self, queue_name, message):
        connection = None
        try:
            connection = self._connect()
            channel = connection.channel()
            channel.queue_declare(queue=queue_name, durable=True) # durable=True to make sure queue survives RabbitMQ restarts
            channel.basic_publish(
                exchange='',
                routing_key=queue_name,
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=2,  # make message persistent
                )
            )
            print(f" [x] Sent '{message}' to queue '{queue_name}'")
        except pika.exceptions.AMQPConnectionError as e:
            print(f"Error connecting to RabbitMQ: {e}")
        finally:
            if connection:
                connection.close()

class TaskConsumer(RabbitMQClient):
    def __init__(self, host='localhost', port=5672):
        super().__init__(host, port)
        self.connection = None
        self.channel = None

    def _callback(self, ch, method, properties, body):
        print(f" [x] Received '{body.decode()}'")
        time.sleep(body.count(b'.')) # Simulate work
        print(" [x] Done")
        ch.basic_ack(delivery_tag=method.delivery_tag)

    def start_consuming(self, queue_name):
        try:
            self.connection = self._connect()
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=queue_name, durable=True)
            self.channel.basic_qos(prefetch_count=1) # Don't dispatch a new message to a worker until it has processed and acknowledged the previous one
            self.channel.basic_consume(queue=queue_name, on_message_callback=self._callback)

            print(f' [*] Waiting for messages in queue "{queue_name}". To exit press CTRL+C')
            self.channel.start_consuming()
        except pika.exceptions.AMQPConnectionError as e:
            print(f"Error connecting to RabbitMQ: {e}")
        except KeyboardInterrupt:
            print("Consumer stopped by user.")
        finally:
            if self.connection and self.connection.is_open:
                self.connection.close()

def run_publisher():
    publisher = TaskPublisher()
    queue_name = 'task_queue'
    for i in range(1, 11):
        task_message = f"Task {i}" + "." * (i % 5 + 1) # Varying work
        publisher.publish_task(queue_name, task_message)
        time.sleep(1)

def run_consumer():
    consumer = TaskConsumer()
    queue_name = 'task_queue'
    consumer.start_consuming(queue_name)

if __name__ == '__main__':
    # You can run publisher and consumer in separate terminals, or using threads for demonstration
    # For a real-world scenario, they would typically be separate processes.

    print("Starting RabbitMQ Publisher and Consumer example...")

    # Start publisher in a separate thread
    publisher_thread = threading.Thread(target=run_publisher)
    publisher_thread.start()

    # Start consumer in the main thread (or another thread if you want multiple consumers)
    # The consumer's start_consuming is a blocking call.
    run_consumer()

    publisher_thread.join() # Wait for publisher to finish if consumer is stopped manually first